const items = $input.all();
return items.map(item => {
  const d = item.json;
  return {
    json: {
      channel: 'email',
      sender_id: d.from?.value?.[0]?.address || d.from || 'unknown',
      sender_name: d.from?.value?.[0]?.name || d.from || 'unknown',
      subject: d.subject || '(no subject)',
      body: (d.text || d.html || '').substring(0, 2000),
      raw_metadata: JSON.stringify({ message_id: d.messageId, date: d.date, to: d.to }),
      status: 'unread'
    }
  };
});
